SELECT

FROM T_DIS_PORT_DAYNIGHTPLAN PDP
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = PDP.SHIPVOYAGE_ITEM_ID
LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = TDSI.SHIPVOYAGE_ID

 TO_CHAR(PLAN_DATE, 'YYYY-MM-DD') = #{planDate}

    and PDP.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}


    and PDP.ClASS_CODE = #{classCode}


    and PDP.CARGO_OWNER_ID = #{cargoOwnerId}




    and PDP.BUSINESS_NO like #{businessNo_like}


    and PDP.PACKING_CODE = #{packingCode}


    and PDP.PORT_CODE = #{portCode}



        AND TDS.SHIP_NAME LIKE #{shipName_like}



        AND TDSI.VOYAGE LIKE #{voyage_like}


ORDER BY CREATE_TIME DESC,ID

SELECT

FROM T_DIS_PORT_DAYNIGHTPLAN PDP
WHERE ID = #{id}

SELECT BT.ID AS TRUST_ID, BTC.ID AS TRUST_CARGO_ID, BTC.BUSINESS_NO, BCI.SHIPVOYAGE_ID, BCI.SHIPVOYAGE_ITEM_ID, CONCAT( DECODE(CONCAT( BCI.SHIP_NAME, '/' ),'/','',CONCAT( BCI.SHIP_NAME, '/' )), DSI.VOYAGE ) AS SHIPVOYAGE_NAME, BCI.SCN, CASE WHEN BTC.CONSIGNER_ID IS NOT NULL THEN BTC.CONSIGNER_ID ELSE BCI.CARGO_OWNER_ID END AS CARGO_OWNER_ID, CASE WHEN BTC.CONSIGNER_ID IS NOT NULL THEN BTC.CONSIGNER_NAME ELSE BCI.CARGO_OWNER_NAME END AS CARGO_OWNER_NAME, BT.PORT_CODE, BT.PORT_NAME, BCI.CARGO_CODE, BCI.CARGO_NAME, BCI.PACKING_CODE, BCI.PACKING_NAME, BT.TRADE_TYPE, BTC.TON, BT.TYPE AS NOTICE_TYPE FROM T_BUS_TRUST BT INNER JOIN T_BUS_TRUST_CARGO BTC ON BT.ID = BTC.TRUST_ID INNER JOIN T_BUS_CARGO_INFO BCI ON BTC.CARGO_INFO_ID = BCI.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM DSI ON BCI.SHIPVOYAGE_ITEM_ID = DSI.ID WHERE BT.TRUST_TYPE = '2'
AND BT.TYPE IN ('集港', '疏港','陆销') AND BT.PORT_CODE IS NOT NULL
AND BCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND BCI.CARGO_OWNER_ID = #{cargoOwnerId}
AND BCI.CARGO_CODE = #{cargoCode}
AND BTC.BUSINESS_NO LIKE #{businessNoLike}
AND ((TO_DATE(#{searchDate},'YYYY-MM-DD') BETWEEN TO_DATE(TO_CHAR(BT.START_TIME - INTERVAL '1' DAY,'YYYY-MM-DD'),'YYYY-MM-DD') AND TO_DATE(TO_CHAR(BT.END_TIME,'YYYY-MM-DD'),'YYYY-MM-DD')) OR BT.START_TIME IS NULL OR BT.END_TIME IS NULL)
ORDER BY REPLACE(SUBSTR(BUSINESS_NO, 2), '_', '') DESC

SELECT

FROM T_DIS_PORT_DAYNIGHTPLAN PDP
WHERE
BUSINESS_NO = #{businessNo}
AND
TO_CHAR(END_TIME, 'yyyy-MM-dd HH:mi:ss') >= #{planDate}
AND
TO_CHAR(BEGIN_TIME, 'yyyy-MM-dd HH:mi:ss') <= #{planDate}
ORDER BY CREATE_TIME DESC,ID

